// src/pages/admin/AdminDashboard.js
import React, { useEffect, useState } from "react";
import {
  getOverview,
  getUsers,
  getRiders,
  getApprovedCaptains,
  getPendingCaptains,
  approveCaptain,
  rejectCaptain,
  getRides,
} from "../../services/adminApi";
import {
  Box,
  Paper,
  Typography,
  Grid,
  Button,
  Table,
  TableHead,
  TableBody,
  TableRow,
  TableCell,
  IconButton,
} from "@mui/material";
import PeopleIcon from "@mui/icons-material/People";
import EmojiPeopleIcon from "@mui/icons-material/EmojiPeople";
import PendingActionsIcon from "@mui/icons-material/PendingActions";
import VerifiedUserIcon from "@mui/icons-material/VerifiedUser";
import LocalTaxiIcon from "@mui/icons-material/LocalTaxi";
import LogoutIcon from "@mui/icons-material/Logout";

import { useAuth } from "../../contexts/AuthContext";
import { useNavigate } from "react-router-dom";

export default function AdminDashboard() {
  const [overview, setOverview] = useState({});
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState("Users"); // default

  const { logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate("/admin");
  };

  const fetchOverview = async () => {
    try {
      setLoading(true);
      const overviewRes = await getOverview();
      setOverview(overviewRes.data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const fetchDataByTab = async (tab) => {
    try {
      setLoading(true);
      let res;
      switch (tab) {
        case "Users":
          res = await getUsers();
          setData(res.data.users);
          break;
        case "Riders":
          res = await getRiders();
          setData(res.data.riders);
          break;
        case "Approved Captains":
          res = await getApprovedCaptains();
          setData(res.data.captains);
          break;
        case "Pending Captains":
          res = await getPendingCaptains();
          setData(res.data.pendingCaptains);
          break;
        case "Rides":
          res = await getRides();
          setData(res.data.rides);
          break;
        default:
          setData([]);
      }
    } catch (err) {
      console.error(err);
      setData([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchOverview();
    fetchDataByTab(activeTab);
  }, [activeTab]);

  const handleApprove = async (id) => {
    await approveCaptain(id);
    fetchDataByTab("Pending Captains");
    fetchOverview();
  };

  const handleReject = async (id) => {
    await rejectCaptain(id);
    fetchDataByTab("Pending Captains");
    fetchOverview();
  };

  const cardData = [
    { label: "Users", value: overview.users, icon: <PeopleIcon fontSize="large" color="primary" /> },
    { label: "Riders", value: overview.riders, icon: <EmojiPeopleIcon fontSize="large" color="success" /> },
    { label: "Approved Captains", value: overview.captains, icon: <VerifiedUserIcon fontSize="large" color="secondary" /> },
    { label: "Pending Captains", value: overview.pendingCaptains, icon: <PendingActionsIcon fontSize="large" color="warning" /> },
    { label: "Total Rides", value: overview.rides, icon: <LocalTaxiIcon fontSize="large" color="error" /> },
  ];

  const renderTable = () => {
    if (loading) return <Typography>Loading...</Typography>;
    if (!data || data.length === 0) return <Typography>No data found.</Typography>;

    if (activeTab === "Rides") {
      return (
        <Table>
          <TableHead>
            <TableRow>
              <TableCell>Rider</TableCell>
              <TableCell>Captain</TableCell>
              <TableCell>Pickup</TableCell>
              <TableCell>Drop</TableCell>
              <TableCell>Fare</TableCell>
              <TableCell>Status</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {data.map((ride) => (
              <TableRow key={ride._id}>
                <TableCell>{ride.riderId?.fullName || "-"}</TableCell>
                <TableCell>{ride.captainId?.fullName || "-"}</TableCell>
                <TableCell>{ride.pickup}</TableCell>
                <TableCell>{ride.drop}</TableCell>
                <TableCell>{ride.fare}</TableCell>
                <TableCell>{ride.status}</TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      );
    }

    return (
      <Table>
        <TableHead>
          <TableRow>
            <TableCell>Name</TableCell>
            <TableCell>Email</TableCell>
            <TableCell>Mobile</TableCell>
            <TableCell>Role</TableCell>
            <TableCell>Login Count</TableCell>
            <TableCell>Approval Status</TableCell>
            {activeTab === "Pending Captains" && <TableCell>Actions</TableCell>}
          </TableRow>
        </TableHead>
        <TableBody>
          {data.map((item) => (
            <TableRow key={item._id}>
              <TableCell>{item.fullName}</TableCell>
              <TableCell>{item.email}</TableCell>
              <TableCell>{item.mobile}</TableCell>
              <TableCell>{item.role}</TableCell>
              <TableCell>{item.loginCount || 0}</TableCell>
              <TableCell>{item.approvalStatus}</TableCell>
              {activeTab === "Pending Captains" && (
                <TableCell>
                  <Button
                    variant="contained"
                    color="success"
                    size="small"
                    sx={{ mr: 1 }}
                    onClick={() => handleApprove(item._id)}
                  >
                    Approve
                  </Button>
                  <Button
                    variant="contained"
                    color="error"
                    size="small"
                    onClick={() => handleReject(item._id)}
                  >
                    Reject
                  </Button>
                </TableCell>
              )}
            </TableRow>
          ))}
        </TableBody>
      </Table>
    );
  };

  return (
    <Box>
      <Box display="flex" justifyContent="space-between" alignItems="center" mb={2}>
        <Typography variant="h4">Admin Dashboard</Typography>
        <Button variant="outlined" color="secondary" startIcon={<LogoutIcon />} onClick={handleLogout}>
          Logout
        </Button>
      </Box>

      <Grid container spacing={2}>
        {cardData.map((card) => (
          <Grid item xs={12} sm={6} md={2.4} key={card.label}>
            <Paper
              sx={{
                p: 2,
                display: "flex",
                alignItems: "center",
                gap: 1,
                cursor: "pointer",
                backgroundColor: activeTab === card.label ? "rgba(0,0,0,0.05)" : "inherit",
              }}
              onClick={() => setActiveTab(card.label)}
            >
              {card.icon}
              <Box>
                <Typography variant="h6">{card.value}</Typography>
                <Typography variant="body2">{card.label}</Typography>
              </Box>
            </Paper>
          </Grid>
        ))}
      </Grid>

      <Box mt={3}>{renderTable()}</Box>
    </Box>
  );
}
